class Solution:
    def diStringMatch(self, s: str):
        n = len(s)
        perm = [0] * (n + 1)
        lo, hi = 0, n
        for i, c in enumerate(s):
            if c == 'I':
                perm[i] = lo
                lo += 1
            else:
                perm[i] = hi
                hi -= 1
        perm[n] = lo  # lo == hi at this point
        return perm

